        runId: String(session["runId"]),
        sequence: 100,
        payload: { text: "hello" },
        createdAt: "2026-05-11T00:00:00.000Z"
      };
      yield {
        id: "event_adapter_completed",
        type: "run.completed",
        runId: String(session["runId"]),
        sequence: 101,
        payload: { status: "completed" },
        createdAt: "2026-05-11T00:00:00.000Z"
      };
    })();
  }
}

